parameters.jsCode:
// Telegram callback_data is limited to 64 bytes. UUID + 'approve:' fits easily.
const body = $json.body || $json;
return [{ json: {
  record_id:        body.record_id,
  complainant_name: body.complainant_name,
  incident_date:    body.incident_date,
  fir_excerpt:      (body.fir_text || '').slice(0, 700),
  approveData:      'approve:' + body.record_id,
  rejectData:       'reject:'  + body.record_id
}}];

parameters.jsonBody:
={{ JSON.stringify({
  chat_id: $env.TELEGRAM_CHAT_ID,
  text: '📋 *FIR Pending Review*

*Complainant:* ' + $json.complainant_name + '
*Incident Date:* ' + $json.incident_date + '
*Record ID:* `' + $json.record_id + '`

*Drafted FIR (excerpt):*
```
' + $json.fir_excerpt + '
```

Review the draft above and tap a button below.',
  parse_mode: 'Markdown',
  reply_markup: {
    inline_keyboard: [[
      { text: '✅ Approve', callback_data: $json.approveData },
      { text: '❌ Reject',  callback_data: $json.rejectData  }
    ]]
  }
}) }}
